function selectPlantType(el,name,emoji,days,savings){document.querySelectorAll('.plant-option').forEach(o=>o.classList.remove('selected'));el.classList.add('selected');selectedPlantData={name,emoji,days,savings};}
function addPlant(){if(!selectedPlantData){showToast('⚠️ Please select a plant type');return;}const loc=document.getElementById('plant-location').value.trim()||'Balcony';const d=parseInt(document.getElementById('plant-days').value)||0;myPlants.push({id:Date.now(),type:selectedPlantData.name,emoji:selectedPlantData.emoji,location:loc,daysPlanted:d,totalDays:selectedPlantData.days,addedAt:Date.now()});saveGarden();hideAddPlant();renderGarden();showToast('🌱 '+selectedPlantData.name+' added to your garden!');}

// STREAK
function updateStreak(){let streak=ld(STK,{count:0,lastDate:''});const today=new Date().toDateString();if(streak.lastDate!==today){streak.count=(streak.lastDate===new Date(Date.now()-86400000).toDateString()?streak.count+1:1);streak.lastDate=today;sv(STK,streak);}setEl('streak-count',streak.count);setEl('streak-days',streak.count);}

