function addAnalyzerToCart(price,name,emoji){if(analyzerCartItems.includes(name)){showToast('Already added!');return;}analyzerCartItems.push(name);const id=Object.keys(products).find(k=>products[k].name===name);if(id){addItem(id);}else{const newId=100+analyzerCartItems.length;cart[newId]={qty:1,name,price,emoji};updateCartUI();}showToast('✅ '+name+' added to cart!');}
