// NAV — history-based navigation so Back goes one step back, not always Home
let _navHistory=[];
// map of which bottom-nav tab to highlight per screen — MUST stay in sync with
// SCREEN_PAGE in the MPA navigation patch at the bottom of this file. Every
// screen that lives on a given page highlights that page's bottom-nav tab.
const NAV_PARENT={
  // home page screens
  splash:'home', login:'home', home:'home', wellness:'home', eating:'home',
  learn:'home', kids:'home', aicoach:'home', more:'home',
  // shop page screens
  shop:'shop', cart:'shop', wishlist:'shop', future:'shop', upi:'shop', success:'shop',
  // garden page screens
  garden:'garden', expert:'garden', calendar:'garden', analyzer:'garden',
  soil:'garden', compost:'garden',
  // community page screens
  community:'community', family:'community', familymembers:'community',
  // profile page screens
  profile:'profile', editprofile:'profile', orders:'profile', rewards:'profile',
  subs:'profile', rd:'profile', rdfull:'profile'
};
const NAV_HIDE_PAGES=['splash','login'];
function _updateNav(name){
  // Legacy SPA had a single #globalBottomNav element OUTSIDE .phone. In the
  // MPA split, every page ships its own <a href> .bottom-nav INSIDE .phone,
  // so the legacy node must stay hidden — otherwise it floats below the phone
  // frame on desktop. We still update the .active state of whichever real
  // bottom-nav is on this page so the highlight follows the active screen.
  var legacy=document.getElementById('globalBottomNav');
  if(legacy) legacy.style.display='none';
  if(NAV_HIDE_PAGES.indexOf(name)>=0) return;
  // Highlight the bottom-nav tab that OWNS this screen (destination wins).
  // The user is currently looking at this screen, so its host page is the
  // truthful indicator — even if they arrived via a cross-page redirect.
  // `?from=` is still preserved on the URL so goBack() can return to the
  // originating page, but it no longer influences the highlight.
  var parent = NAV_PARENT[name] || name;
  document.querySelectorAll('.phone > .bottom-nav .nav-item').forEach(function(it){
    var t=it.getAttribute('data-tab');
    // For <a href> nav, derive tab from the href if data-tab isn't present
    if(!t){
      var href=(it.getAttribute('href')||'').split('?')[0];
      var map={'growfresh-app.html':'home','shop.html':'shop','garden.html':'garden','community.html':'community','profile.html':'profile'};
      t=map[href];
    }
    it.classList.toggle('active', t===parent);
  });
}
function showScreen(name,opts){
  opts=opts||{};
  const cur=document.querySelector('.screen.active');
  const curName=cur?cur.id.replace('screen-',''):null;
  if(!opts.fromBack && curName && curName!==name){_navHistory.push(curName);}
  document.querySelectorAll('.screen').forEach(s=>s.classList.remove('active'));
  const el=document.getElementById('screen-'+name);if(el)el.classList.add('active');
  // ── Per-screen render dispatch ───────────────────────────────
  // Every data-driven screen MUST have its render hook here so that
  // cross-page navigation (?screen=calendar etc.) also paints content,
  // not just switchTab() in-page calls.
  try {
    if(name==='home'){
      // Re-paint home widgets so WFH "1 Hour for Yourself" status, plants,
      // greeting, and tips stay in sync when navigating back from another
      // screen (e.g. after sharing the achievement, or completing a break
      // on a different page).
      try{ if(typeof renderHomePlants==='function') renderHomePlants(); }catch(e){}
      try{ if(typeof renderHomeTips==='function') renderHomeTips(); }catch(e){}
      try{ if(typeof renderWfh==='function') renderWfh(); }catch(e){}
      try{ if(typeof updateGreeting==='function') updateGreeting(); }catch(e){}
      try{ if(typeof refreshHomeBadges==='function') refreshHomeBadges(); }catch(e){}
    }
    else if(name==='garden'){ renderGarden(); try{ if(typeof gfRefreshGardenPicks==='function') gfRefreshGardenPicks(); }catch(e){} }
    else if(name==='calendar' && typeof renderPlantTimeline==='function') renderPlantTimeline();
    else if(name==='cart' && typeof renderCartItems==='function'){
      // Mirror goToCart()'s empty-state toggle so cart is never blank
      var items=Object.values(cart||{});
      var qty=items.reduce(function(s,i){return s+i.qty;},0);
      var ct=document.getElementById('cart-count-text'); if(ct) ct.textContent=qty+' item'+(qty!==1?'s':'');
      var em=document.getElementById('empty-cart'), sc=document.getElementById('cart-scroll');
      if(em && sc){
        if(qty===0){em.style.display='flex';sc.style.display='none';}
        else{em.style.display='none';sc.style.display='block';renderCartItems();}
      }
    }
    else if(name==='wishlist' || name==='future'){
      // Both render functions are private to the wishlist/future IIFE but
      // refreshAll exposes them indirectly. Call it if available.
      if(typeof window.refreshAll==='function') window.refreshAll();
    }
    else if(name==='editprofile') loadProfileForEdit();
    else if(name==='familymembers') renderFamilyMembers();
    else if(name==='kids' && typeof window.renderStars==='function') window.renderStars();
    else if(name==='aicoach' && typeof window.gfRefreshAiCoach==='function') window.gfRefreshAiCoach();
  } catch(e) { console.warn('[gf] render hook failed for screen', name, e); }
  // Re-translate any content the render hooks just injected (Garden cards,
  // Family Members list, Edit Profile inputs, Smart Picks, etc.)
  try{ if(typeof _gfRetranslate==='function') _gfRetranslate(); }catch(e){}
  if(name==='community'){
    // Always reset to the default "All" filter when entering Community fresh — don't
    // carry over a Tips/Harvest/Questions selection from a previous visit.
    try{
      window.currentFeedFilter='all';
      if(typeof currentFeedFilter!=='undefined') currentFeedFilter='all';
      var _ftabs=document.querySelectorAll('#screen-community .feed-tab');
      _ftabs.forEach(function(t,i){t.classList.toggle('active', i===0);});
    }catch(e){}
    renderCommunityFeed();
  }
  if(name==='shop'){
    // Clear any leftover search text from a previous visit — search state must
    // not survive page navigation.
    try{
      var _ss=document.getElementById('shop-search');
      if(_ss){ _ss.value=''; if(typeof window.onShopSearch==='function') window.onShopSearch(''); }
    }catch(e){}
  }
  _updateNav(name);
}
function goBack(){
  // If user arrived via a cross-page redirect (?from=community on garden.html
  // when opening Expert), back must return to the originating page, NOT to
  // the host page's default screen.
  try{
    if (window.__gfNavFrom) {
      var PAGE_FILE = {home:'growfresh-app.html', shop:'shop.html', garden:'garden.html', community:'community.html', profile:'profile.html'};
      var dest = PAGE_FILE[window.__gfNavFrom];
      var here = (location.pathname||'').split('/').pop() || 'growfresh-app.html';
      if (dest && dest !== here) {
        // Clear so the destination doesn't think IT was cross-page nav.
        window.__gfNavFrom = null;
        location.href = dest;
        return;
      }
    }
  }catch(e){}
  if(_navHistory.length>0){const prev=_navHistory.pop();showScreen(prev,{fromBack:true});}
  else{showScreen('home',{fromBack:true});}
}
function switchTab(tab,cat){
  const map={home:'home',shop:'shop',garden:'garden',community:'community',profile:'profile',expert:'expert',calendar:'calendar',analyzer:'analyzer',subs:'subs',more:'more',rewards:'rewards',learn:'learn',soil:'soil',compost:'compost',wellness:'wellness',eating:'eating',aicoach:'aicoach',orders:'orders',editprofile:'editprofile',familymembers:'familymembers',family:'family',cart:'cart',wishlist:'wishlist',future:'future',rd:'rd',kids:'kids'};
  showScreen(map[tab]||tab);
  if(tab==='calendar')renderPlantTimeline();
  if(tab==='shop'&&cat){
    // wait for screen swap, then activate the matching category pill
    // (Minerals & Compost share one pill, so map either to the group key)
    var pillCat=(cat==='minerals'||cat==='compost')?'minerals,compost':cat;
    setTimeout(()=>{
      const pills=document.querySelectorAll('#screen-shop .cat-pill');
      pills.forEach(p=>{
        const onclickAttr=p.getAttribute('onclick')||'';
        if(onclickAttr.includes("'"+pillCat+"'")){filterCat(p,pillCat);}
      });
    },30);
  }
}
function filterCat(pill,cat){
  // Only clear active state on the main category strip (not the sub-strip),
  // so clicking a tools sub-pill doesn't deactivate the parent Tools pill.
  document.querySelectorAll('#screen-shop .cat-strip:not(#tools-substrip) .cat-pill').forEach(p=>p.classList.remove('active'));
  if(pill&&pill.classList)pill.classList.add('active');
  // `cat` may be a single key ("seeds"), a comma-joined group
  // ("minerals,compost"), or a sub-cat selector ("tools:hand-tools").
  // The sub-cat form filters within Tools by data-subcat.
  var rawCats=String(cat||'all').split(',').map(function(s){return s.trim();});
  var subcatFilter=null;
  var cats=rawCats.map(function(c){
    var p=c.indexOf(':');
    if(p>=0){ subcatFilter=c.slice(p+1); return c.slice(0,p); }
    return c;
  });
  var all=cats.indexOf('all')!==-1;
  document.querySelectorAll('.product-card').forEach(function(c){
    var match=all||cats.indexOf(c.dataset.cat)!==-1;
    if(match && subcatFilter && subcatFilter!=='all'){
      match = (c.dataset.subcat===subcatFilter);
    }
    c.style.display=match?'flex':'none';
  });
  // Show/hide the Tools sub-pill strip
  try{ _gfRenderToolsSubStrip(cats.indexOf('tools')!==-1, subcatFilter); }catch(e){}
}

/* Tools sub-category strip — appears only when Tools pill is active.
   Mirrors the .cat-strip styling. Pills filter tools by data-subcat.
   Sub-categories are loaded from db/shop-config.json (with inline fallback). */
function _gfRenderToolsSubStrip(show, activeSub){
  var strip=document.getElementById('tools-substrip');
  var hostStrip=document.querySelector('#screen-shop .cat-strip');
  if(!hostStrip) return;
  if(!strip){
    strip=document.createElement('div');
    strip.id='tools-substrip';
    strip.className='cat-strip';
    strip.style.cssText='margin-top:6px;display:none;overflow-x:auto;-webkit-overflow-scrolling:touch';
    hostStrip.parentNode.insertBefore(strip, hostStrip.nextSibling);
  }
  if(!show){ strip.style.display='none'; return; }
  var cfg=(window.GF_SHOP_CONFIG && window.GF_SHOP_CONFIG.subcatsByCat && window.GF_SHOP_CONFIG.subcatsByCat.tools) || [
    {key:'all',          label:'All Tools',   emoji:'🧰'},
    {key:'hand-tools',   label:'Hand Tools',  emoji:'🪒'},
    {key:'irrigation',   label:'Irrigation',  emoji:'💧'},
    {key:'containers',   label:'Containers',  emoji:'🛍️'},
    {key:'support',      label:'Support',     emoji:'🎍'},
    {key:'protection',   label:'Protection',  emoji:'☂️'},
    {key:'diagnostics',  label:'Diagnostics', emoji:'📟'},
    {key:'propagation',  label:'Propagation', emoji:'🌱'},
    {key:'pest-control', label:'Pest-Control',emoji:'🪤'},
    {key:'safety-gear',  label:'Safety',      emoji:'🧤'}
  ];
  var active=activeSub||'all';
  strip.innerHTML=cfg.map(function(s){
    var cls='cat-pill'+(s.key===active?' active':'');
    var arg=s.key==='all'?'tools':'tools:'+s.key;
    var lbl=(s.emoji?s.emoji+' ':'')+s.label;
    return '<div class="'+cls+'" onclick="filterCat(this,\''+arg+'\')" style="font-size:11px;padding:4px 9px">'+lbl+'</div>';
  }).join('');
  strip.style.display='flex';
}

/* Rebuild the main cat-strip + region select from db/shop-config.json so the
   HTML stays minimal and editors don't have to touch markup to add a category
   or region. Safe to call multiple times — idempotent. */
function _gfRenderShopChrome(){
  var cfg = window.GF_SHOP_CONFIG; if (!cfg) return;
  var strip = document.querySelector('#screen-shop .cat-strip:not(#tools-substrip)');
  if (strip && Array.isArray(cfg.categories) && cfg.categories.length){
    // Preserve current active key (default to first)
    var activeKey = (strip.querySelector('.cat-pill.active')||{}).getAttribute && strip.querySelector('.cat-pill.active').getAttribute('data-cat-key');
    if (!activeKey){
      var firstActive = strip.querySelector('.cat-pill.active');
      if (firstActive){
        var m = (firstActive.getAttribute('onclick')||'').match(/filterCat\(this,'([^']+)'\)/);
        activeKey = m ? m[1] : cfg.categories[0].key;
      } else activeKey = cfg.categories[0].key;
    }
    strip.innerHTML = cfg.categories.map(function(c){
      var lbl = (c.emoji?c.emoji+' ':'') + c.label;
      var cls = 'cat-pill' + (c.key===activeKey?' active':'');
      return '<div class="'+cls+'" data-cat-key="'+c.key+'" onclick="filterCat(this,\''+c.key+'\')">'+lbl+'</div>';
    }).join('');
  }
  var sel = document.getElementById('shop-region');
  if (sel && Array.isArray(cfg.regions) && cfg.regions.length){
    var cur = sel.value || 'all';
    sel.innerHTML = cfg.regions.map(function(r){
      return '<option value="'+r.value+'"'+(r.value===cur?' selected':'')+'>'+r.label+'</option>';
    }).join('');
  }
  // Delivery banner (cart screen)
  var del = document.querySelector('.delivery-note');
  if (del && cfg.freeDeliveryAbove != null){
    del.textContent = '🚚 Free delivery above ₹'+cfg.freeDeliveryAbove+' · '+(cfg.deliveryEta||'')+' · '+(cfg.deliveryCity||'');
  }
}

/* Fetch db/shop-config.json once and cache. Resolves with the config object. */
function _gfLoadShopConfig(){
  if (window.GF_SHOP_CONFIG) return Promise.resolve(window.GF_SHOP_CONFIG);
  var base = (function(){
    var s = document.currentScript || document.querySelector('script[src*="gf-app.js"]');
    if (s && s.src) return s.src.replace(/\/shared\/gf-app\.js.*$/, '/db/');
    return 'db/';
  })();
  // Use cached copy synchronously while the network request runs.
  try{
    var cached = localStorage.getItem('gf_shop_config_v1');
    if (cached){
      var c = JSON.parse(cached);
      if (c && typeof c==='object') window.GF_SHOP_CONFIG = c;
    }
  }catch(e){}
  return fetch(base + 'shop-config.json', { cache:'force-cache' })
    .then(function(r){ return r.ok ? r.json() : null; })
    .then(function(j){
      if (j && typeof j==='object'){
        window.GF_SHOP_CONFIG = j;
        try{ localStorage.setItem('gf_shop_config_v1', JSON.stringify(j)); }catch(e){}
      }
      return window.GF_SHOP_CONFIG;
    })
    .catch(function(){ return window.GF_SHOP_CONFIG || null; });
}
if (typeof window!=='undefined'){
  window._gfLoadShopConfig = _gfLoadShopConfig;
  window._gfRenderShopChrome = _gfRenderShopChrome;
}
// Deep-link from anywhere into a specific product card on the Shop page.
// Switches to Shop, applies the category filter, then scrolls to and pulses
// the matching card (matched by exact product-name text).
// MPA-aware: if Shop lives on another page, hands the product name to the
// URL (?product=) so shop.html can resolve it after render.
function gotoProduct(name,cat){
  var hostHasShop = !!document.getElementById('screen-shop');
  if (!hostHasShop){
    // Cross-page hop: encode product in URL; shop.html will pulse it on load.
    var file = (typeof fileForScreen==='function' ? fileForScreen('shop') : 'shop.html') || 'shop.html';
    var from = (typeof currentPageKey==='function' ? currentPageKey() : 'home');
    var qs = '?screen=shop'
           + (cat ? ('&cat=' + encodeURIComponent(cat)) : '')
           + '&product=' + encodeURIComponent(name)
           + '&from=' + encodeURIComponent(from);
    location.href = file + qs;
    return;
  }
  switchTab('shop',cat||'all');
  setTimeout(()=>{
    const cards=document.querySelectorAll('#screen-shop .product-card');
    let target=null;
    cards.forEach(c=>{
      const n=c.querySelector('.product-name');
      if(n&&n.textContent.trim().toLowerCase()===String(name).trim().toLowerCase())target=c;
    });
    if(!target)return;
    target.scrollIntoView({behavior:'smooth',block:'center'});
    target.classList.add('product-pulse');
    setTimeout(()=>target.classList.remove('product-pulse'),1600);
  },120);
}

