/* ════════════════ i18n — preferred language via Google Translate ════════════════
   Stores choice in localStorage('gf_lang') + the googtrans cookie that the
   Google widget reads. The widget is injected hidden; we drive it through
   the cookie so the UI stays in our control. Supports en/te/hi/ta/kn.   */
var GF_LANG_KEY='gf_lang';
function _gfSetCookie(name, value, days){
  var exp = new Date(Date.now() + days*86400*1000).toUTCString();
  // Set on host + on parent domain (needed by Google widget for some setups)
  document.cookie = name+'='+value+';expires='+exp+';path=/';
  var host = location.hostname.replace(/^www\./,'');
  if(host && host.indexOf('.')>0){
    document.cookie = name+'='+value+';expires='+exp+';path=/;domain=.'+host;
  }
}
function gfApplyLanguage(code){
  code = (code||'en').toLowerCase();
  // Kannada removed — Google Translate widget produces duplicated UI on
  // certain emoji + Kannada-glyph combinations. English/Telugu/Hindi/Tamil
  // only for now. Users wanting Kannada can use the browser's built-in
  // translate (Chrome menu → Translate).
  var map = { en:'en', te:'te', hi:'hi', ta:'ta' };
  var dst = map[code] || 'en';
  try{ localStorage.setItem(GF_LANG_KEY, dst); }catch(e){}
  if(dst === 'en'){
    _gfSetCookie('googtrans','', -1);
    document.cookie = 'googtrans=; path=/; expires=Thu, 01 Jan 1970 00:00:00 GMT';
  } else {
    _gfSetCookie('googtrans', '/en/'+dst, 365);
  }
  setTimeout(function(){ location.reload(); }, 150);
}
function _gfKillBanner(){
  // Remove ONLY the banner iframe (class .goog-te-banner-frame). Do NOT
  // touch other iframes with class .skiptranslate — one of those is the
  // translation worker and removing it kills the whole feature.
  var iframes = document.querySelectorAll('iframe.goog-te-banner-frame');
  iframes.forEach(function(f){ try{ f.parentNode && f.parentNode.removeChild(f); }catch(e){} });
  var tt = document.getElementById('goog-gt-tt'); if(tt) tt.style.display='none';
  if(document.body){
    document.body.style.top = '0px';
    document.body.style.position = '';
  }
}
/* Re-translation strategy (post-loop-bug rewrite):
   - When the user picks a language in Edit Profile, we set the googtrans
     cookie and reload ONCE. From then on, Google auto-translates on every
     page navigation because the cookie is read on each page load.
   - We do NOT toggle the widget select in-place. That approach wrapped
     text in nested <font> tags and duplicated emojis/logos visually.
   - Dynamic content rendered after page load (Garden cards, Smart Picks)
     will appear in English briefly; Google's own internal observer picks
     it up within ~1s. This is the trade-off for not breaking the UI. */
var _gfRetransPending = null;
function _gfRetranslate(){ /* intentional no-op — see comment above */ }
if(typeof window!=='undefined'){ window._gfRetranslate = _gfRetranslate; }
function _gfBootGoogleTranslate(){
  if(window.top !== window) return;
  // Body may not exist if called from <head>-stage script
  if(!document.body){
    document.addEventListener('DOMContentLoaded', function(){ _gfBootGoogleTranslate(); }, { once:true });
    return;
  }
  if(!document.getElementById('google_translate_element')){
    var host = document.createElement('div');
    host.id = 'google_translate_element';
    document.body.appendChild(host);   // CSS positions it off-screen
  }
  if(!document.getElementById('gf-gt-css')){
    var css = document.createElement('style');
    css.id = 'gf-gt-css';
    css.textContent = ''
      + '.goog-te-banner-frame,.goog-te-banner-frame.skiptranslate,iframe.skiptranslate{display:none!important;visibility:hidden!important;height:0!important;width:0!important;border:0!important}'
      + '.goog-te-gadget-icon,.goog-te-gadget-simple{display:none!important}'
      + 'body{top:0!important;position:static!important}'
      + 'html{margin-top:0!important}'
      + '#goog-gt-tt,.goog-tooltip,.goog-tooltip:hover,.goog-text-highlight{display:none!important;background:none!important;box-shadow:none!important;border:0!important}'
      + '.skiptranslate>iframe{display:none!important}';
    document.head.appendChild(css);
  }
  window.googleTranslateElementInit = function(){
    try{
      new google.translate.TranslateElement({
        pageLanguage: 'en',
        includedLanguages: 'en,te,hi,ta',
        autoDisplay: false,
        layout: google.translate.TranslateElement.InlineLayout.SIMPLE
      }, 'google_translate_element');
      // Kill banner immediately + observe future injections
      _gfKillBanner();
      var obs = new MutationObserver(function(){ _gfKillBanner(); });
      obs.observe(document.documentElement, { childList:true, subtree:true });
      // Stop observing after 10s — banner only appears at boot
      setTimeout(function(){ try{ obs.disconnect(); }catch(e){} }, 10000);
    }catch(e){ console.warn('[gf-i18n] widget init failed', e); }
  };
  if(!document.getElementById('gf-gt-script')){
    var s = document.createElement('script');
    s.id = 'gf-gt-script';
    s.src = 'https://translate.google.com/translate_a/element.js?cb=googleTranslateElementInit';
    s.async = true;
    s.onerror = function(){ console.warn('[gf-i18n] could not load Google Translate widget'); };
    document.head.appendChild(s);
  }
}
if(typeof window!=='undefined'){
  window.gfApplyLanguage = gfApplyLanguage;
  // Re-affirm cookie ASAP (before any text is painted in source language)
  try{
    var _saved = localStorage.getItem(GF_LANG_KEY) || '';
    // Migrate users who previously picked 'kn' (now unsupported) back to English
    if(_saved === 'kn'){
      _saved = 'en';
      try{ localStorage.setItem(GF_LANG_KEY, 'en'); }catch(e){}
      _gfSetCookie('googtrans','', -1);
      document.cookie = 'googtrans=; path=/; expires=Thu, 01 Jan 1970 00:00:00 GMT';
    }
    if(_saved && _saved !== 'en' && document.cookie.indexOf('googtrans=/en/'+_saved) < 0){
      _gfSetCookie('googtrans', '/en/'+_saved, 365);
    }
  }catch(e){}
  // Boot widget as early as possible — script tag injection works pre-DOM-ready
  // (the script itself waits for body before injecting iframe)
  try{ _gfBootGoogleTranslate(); }catch(e){}
  // Also re-affirm on DOMContentLoaded in case body wasn't ready above
  document.addEventListener('DOMContentLoaded', function(){
    try{ _gfBootGoogleTranslate(); _gfKillBanner(); }catch(e){}
  });
}

// ============ FAMILY MEMBERS ============
function renderFamilyMembers(){
  const list=document.getElementById('family-list');if(!list)return;
  const fm=ld('familyMembers',[]);
  if(fm.length===0){
    list.innerHTML='<div style="background:var(--white);border-radius:var(--radius);padding:20px;text-align:center;box-shadow:var(--shadow-sm);color:var(--muted);font-size:13px;font-weight:700">👨‍👩‍👧 No family members added yet.<br><span style="font-size:11px;font-weight:600;opacity:0.8">Add your first member below</span></div>';
    return;
  }
  const relIcon={Spouse:'💑',Child:'👶',Parent:'👨‍👩‍👧',Sibling:'👫',Other:'🧑'};
  list.innerHTML=fm.map((m,i)=>`
    <div style="background:var(--white);border-radius:var(--radius);padding:12px;box-shadow:var(--shadow-sm);margin-bottom:10px;display:flex;align-items:center;gap:12px">
      <div style="width:44px;height:44px;border-radius:50%;background:var(--green-pale);display:flex;align-items:center;justify-content:center;font-size:22px;flex-shrink:0">${relIcon[m.rel]||'🧑'}</div>
      <div style="flex:1;min-width:0">
        <div style="font-size:14px;font-weight:900;color:var(--text)">${escapeHtml(m.name)}</div>
        <div style="font-size:11px;color:var(--muted);font-weight:700;margin-top:2px">${escapeHtml(m.rel)} · ${m.age} yrs${m.diet?' · '+escapeHtml(m.diet):''}</div>
      </div>
      <button onclick="removeFamilyMember(${i})" style="background:none;border:none;font-size:18px;color:#E53935;cursor:pointer;padding:6px" aria-label="Remove">🗑️</button>
    </div>`).join('');
}
function addFamilyMember(){
  const name=document.getElementById('fm-name').value.trim();
  const rel=document.getElementById('fm-rel').value;
  const age=parseInt(document.getElementById('fm-age').value,10);
  const diet=document.getElementById('fm-diet').value;
  if(!name){showToast('Please enter a name');return;}
  if(!age||age<1||age>120){showToast('Please enter a valid age');return;}
  const fm=ld('familyMembers',[]);
  fm.push({name,rel,age,diet});
  sv('familyMembers',fm);
  document.getElementById('fm-name').value='';
  document.getElementById('fm-age').value='';
  document.getElementById('fm-diet').value='';
  renderFamilyMembers();
  showToast('✓ '+name+' added');
}
function removeFamilyMember(i){
  const fm=ld('familyMembers',[]);
  if(!fm[i])return;
  if(!confirm('Remove '+fm[i].name+' from family?'))return;
  const name=fm[i].name;
  fm.splice(i,1);sv('familyMembers',fm);renderFamilyMembers();
  showToast(name+' removed');
}
function escapeHtml(s){return String(s||'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));}

/* ── block 2 ─────────────────────────────────────────── */
(function(){
  // --- config -----------------------------------------------------
  const qs = new URLSearchParams(location.search);
  const API = (qs.get('api') || window.GF_API || 'http://localhost:5000').replace(/\/$/, '');
  const TK  = 'gf_jwt';

  const getToken  = () => { try { return localStorage.getItem(TK) || ''; } catch(e){ return ''; } };
  const setToken  = (t) => { try { localStorage.setItem(TK, t); } catch(e){} };
  const clearTok  = () => { try { localStorage.removeItem(TK); } catch(e){} };

  // tiny on-screen status pill so you can SEE the wire is live.
  // Hidden by default — only rendered for developers who opt in with
  // ?debug=1 in the URL or window.GF_DEBUG=true. End users never see it,
  // even when the backend is unreachable (calls degrade gracefully).
  const DEBUG_PILL = (qs.get('debug') === '1') || !!window.GF_DEBUG;
  const pill = document.createElement('div');
  pill.id = 'gf-api-pill';
  pill.style.cssText = [
    'position:fixed',
    'left:50%',
    'transform:translateX(-50%)',
    'bottom:6px',
    'z-index:9999',
    'background:rgba(255,255,255,0.92)',
    'color:#2f7a3d',
    'border:1px solid rgba(47,122,61,0.25)',
    'font:600 10px/1 system-ui,-apple-system,sans-serif',
    'padding:4px 9px',
    'border-radius:999px',
    'box-shadow:0 2px 6px rgba(0,0,0,0.08)',
    'cursor:pointer',
    'opacity:0.85',
    'backdrop-filter:blur(6px)',
    '-webkit-backdrop-filter:blur(6px)',
    'pointer-events:auto',
    'user-select:none',
    'display:' + (DEBUG_PILL ? 'block' : 'none'),
  ].join(';');
  pill.textContent = '● connecting';
  pill.title = 'GrowFresh API status — click to copy current JWT';
  pill.onmouseenter = () => { pill.style.opacity = '1'; };
  pill.onmouseleave = () => { pill.style.opacity = '0.85'; };
  pill.onclick = () => {
    if (!getToken()) return;
    navigator.clipboard?.writeText(getToken());
    const prev = pill.textContent;
    pill.textContent = '✓ JWT copied';
    setTimeout(() => { pill.textContent = prev; }, 1200);
  };
  document.body.appendChild(pill);

  let lastStatus = '?';
  function setStatus(txt){
    lastStatus = txt || lastStatus;
    pill.textContent = (getToken() ? '🟢 ' : '⚪ ') + lastStatus;
  }

  async function api(path, { method='GET', body, auth=true } = {}){
    const headers = { 'Content-Type': 'application/json' };
    if (auth && getToken()) headers['Authorization'] = 'Bearer ' + getToken();
    try {
      const res = await fetch(API + path, {
        method, headers,
        body: body ? JSON.stringify(body) : undefined,
      });
      const json = await res.json().catch(()=>({}));
      if (!res.ok) throw new Error(json.msg || ('HTTP '+res.status));
      return json;
    } catch (err) {
      console.warn('[gf-api] '+method+' '+path+' →', err.message);
      setStatus('offline ('+err.message+')');
      throw err;
    }
  }

  // health probe
  api('/api/health', { auth:false })
    .then(()=> setStatus('online'))
    .catch(()=> setStatus('offline – is backend running?'));

  // --- event logging --------------------------------------------------
  const logEvent = (event_type, screen, payload={}) => {
    if (!getToken()) return;             // not logged in yet → drop silently
    api('/api/activity', { method:'POST', body:{ event_type, screen, payload, client:'web' } })
      .then(()=> setStatus('logged ' + event_type))
      .catch(()=>{});
  };

  // --- patch existing functions (preserve original behavior) ---------
  function wrap(name, after){
    const orig = window[name];
    if (typeof orig !== 'function') return;
    window[name] = function(...args){
      const r = orig.apply(this, args);
      try { after.apply(this, args); } catch(e){ console.warn('[gf-api] hook '+name, e); }
      return r;
    };
  }

  // 1️⃣  LOGIN — real OTP call to backend (backend accepts demo OTP "1234")
  wrap('verifyOtp', async function(){
    const mobile = document.getElementById('mobile-input')?.value.trim();
    const otp    = ['otp1','otp2','otp3','otp4'].map(id=>document.getElementById(id)?.value || '').join('');
    if (!mobile || otp.length !== 4) return;
    try {
      const j = await api('/api/auth/verify-otp', { method:'POST', auth:false, body:{ mobile, otp } });
      if (j.token) {
        setToken(j.token);
        setStatus('user '+mobile+' authed');
        // try to push the local profile name back to the server
        try {
          const sess = JSON.parse(localStorage.getItem('gf_s5_sess') || '{}');
          if (sess.name) await api('/api/auth/me', { method:'PUT', body:{ name: sess.name } });
        } catch(e){}
        logEvent('login', 'login', { method:'mobile' });
      }
    } catch(e){ /* offline / wrong otp – the local UI already accepted "1234" */ }
  });

  wrap('logoutUser', function(){
    if (getToken()) logEvent('logout', 'profile');
    clearTok();
    setStatus('logged out');
  });

  // 2️⃣  CART
  wrap('addItem', function(id){
    const p = (window.products || {})[id] || {};
    logEvent('cart_add', 'shop', { product_local_id:id, name:p.name, price:p.price });
  });
  wrap('changeQty', function(id, delta){
    logEvent(delta>0?'cart_inc':'cart_dec', 'cart', { product_local_id:id, delta });
  });

  // 3️⃣  SCREEN VIEWS  (hooked into showScreen)
  wrap('showScreen', function(name){
    logEvent('screen_view', String(name||''), {});
  });

  // 4️⃣  GARDEN — also creates a real user_plants row
  wrap('addPlant', async function(){
    if (!window.selectedPlantData) return;
    try {
      const last = (window.myPlants||[]).slice(-1)[0] || {};
      await api('/api/garden', { method:'POST', body:{
        plantType: window.selectedPlantData.name,
        totalDays: window.selectedPlantData.days || 60,
      }});
      logEvent('plant_added', 'garden', {
        type: window.selectedPlantData.name,
        location: last.location, daysPlanted: last.daysPlanted,
      });
    } catch(e){}
  });

  // 5️⃣  CHECKOUT — call this from a "Place Order" button to persist the cart
  //     as a real order + transaction row.  Exposed as window.gfPlaceOrder so
  //     you can wire any button to it (e.g. add  onclick="gfPlaceOrder()" ).
  window.gfPlaceOrder = async function(addr){
    const cart = window.cart || {};
    const items = Object.entries(cart).map(([localId, c]) => ({
      // we need a real product UUID – pick the first product matching by name
      __local: localId, name: c.name, price: c.price, quantity: c.qty,
    }));
    if (!items.length) { alert('Cart is empty'); return; }
    try {
      // resolve names → real product IDs from the API catalog
      const catalog = await api('/api/products', { auth:false });
      const byName  = Object.fromEntries(catalog.map(p => [p.name.toLowerCase(), p.id]));
      const apiItems = items.map(i => ({
        productId: byName[(i.name||'').toLowerCase()],
        quantity:  i.quantity,
      })).filter(i => i.productId);
      if (!apiItems.length) { alert('No matching products on server'); return; }
      const order = await api('/api/orders', { method:'POST', body:{
        items: apiItems,
        address: addr || { line1:'Demo address', city:'Hyderabad', state:'TG', pincode:'500001' },
        paymentMethod: 'COD',
      }});
      logEvent('order_placed', 'cart', { order_id: order.id || order._id, total: order.total });
      alert('✅ Order placed! id='+(order.id||order._id));
      // clear local cart UI
      Object.keys(window.cart||{}).forEach(k => { delete window.cart[k]; if (window.renderCtrl) window.renderCtrl(k); });
      if (window.updateCartUI) window.updateCartUI();
      return order;
    } catch(e){ alert('Order failed: '+e.message); }
  };

  // 6️⃣  PAYMENT FLOW — when the user taps "Pay … Now" on the UPI screen
  //     mirror the order to the backend (orders + transactions tables).
  //     Runs IN PARALLEL with the existing fake-success animation so the UX
  //     stays exactly the same; the DB just gets the row.
  wrap('confirmPayment', async function(){
    if (!getToken()) { console.log('[gf-api] payment but no JWT – skipping order push'); return; }
    const cart = window.cart || {};
    const items = Object.values(cart);
    if (!items.length) return;
    try {
      const catalog = await api('/api/products', { auth:false });
      const byName  = Object.fromEntries(catalog.map(p => [p.name.toLowerCase(), p.id]));
      const apiItems = Object.values(cart).map(c => ({
        productId: byName[(c.name||'').toLowerCase()],
        quantity:  c.qty,
      })).filter(i => i.productId);
      if (!apiItems.length) { console.warn('[gf-api] no matching products on server'); return; }
      const order = await api('/api/orders', { method:'POST', body:{
        items: apiItems,
        address: { line1:'Demo address', city:'Hyderabad', state:'TG', pincode:'500001' },
        paymentMethod: window.selectedUpiApp ? 'Online' : 'COD',
      }});
      logEvent('order_placed', 'upi', {
        order_id: order.id || order._id,
        total: order.total,
        upi_app: window.selectedUpiApp || 'manual',
      });
      console.log('[gf-api] ✅ order persisted:', order.id || order._id);
      setStatus('order #'+String(order.id||'').slice(0,8)+' saved');
    } catch(e){ console.warn('[gf-api] order persist failed:', e.message); }
  });

  // 7️⃣  FAMILY MEMBERS — every add/remove writes to family_members table.
  //     We keep an index→uuid map in localStorage so removeFamilyMember(idx)
  //     can resolve the right server row.
  const FAM_KEY = 'gf_family_ids';
  const famIds  = () => { try { return JSON.parse(localStorage.getItem(FAM_KEY) || '[]'); } catch(e){ return []; } };
  const setFam  = (a) => { try { localStorage.setItem(FAM_KEY, JSON.stringify(a)); } catch(e){} };

  // After login, hydrate local list with server data so indices stay consistent.
  async function hydrateFamily(){
    if (!getToken()) return;
    try {
      const rows = await api('/api/family');
      const ids  = rows.map(r => r.id);
      setFam(ids);
      // mirror into the localStorage shape the UI uses
      const fm = rows.map(r => ({ name: r.name, rel: r.relation, age: Number(r.age) || '', diet: '' }));
      localStorage.setItem('familyMembers', JSON.stringify(fm));
      if (window.renderFamilyMembers) window.renderFamilyMembers();
    } catch(e){ /* offline – keep local only */ }
  }

  wrap('addFamilyMember', async function(){
    const fm = JSON.parse(localStorage.getItem('familyMembers') || '[]');
    const last = fm[fm.length - 1];
    if (!last) return;
    if (!getToken()) return;
    try {
      const row = await api('/api/family', { method:'POST', body:{
        name: last.name, relation: last.rel, age: last.age, diet: last.diet,
      }});
      const ids = famIds(); ids.push(row.id || row._id); setFam(ids);
      logEvent('family_added', 'familymembers', { name:last.name, relation:last.rel, age:last.age });
      setStatus('family +1');
    } catch(e){ console.warn('[gf-api] family add failed:', e.message); }
  });

  // wrap-BEFORE for remove – capture id by index BEFORE the local splice
  (function(){
    const orig = window.removeFamilyMember;
    if (typeof orig !== 'function') return;
    window.removeFamilyMember = function(i){
      const ids = famIds();
      const id  = ids[i];
      const r   = orig.apply(this, arguments);
      // confirm() may have been declined; only delete server-side if local also went away
      const after = JSON.parse(localStorage.getItem('familyMembers') || '[]');
      const before = ids.length;
      // if local count didn't drop, user cancelled – do nothing
      if (after.length >= before) return r;
      ids.splice(i, 1); setFam(ids);
      if (id && getToken()) {
        api('/api/family/' + id, { method:'DELETE' })
          .then(()=> { logEvent('family_removed', 'familymembers', { id }); setStatus('family -1'); })
          .catch(()=>{});
      }
      return r;
    };
  })();

  // 8️⃣  hydrate family right after login
  const origVerify = window.verifyOtp;
  // (verifyOtp already wrapped above; chain a second hook to hydrate)
  wrap('verifyOtp', function(){
    setTimeout(hydrateFamily, 600);
  });

  // also hydrate immediately if a token already exists from a previous session
  if (getToken()) setTimeout(hydrateFamily, 800);

  console.log('[gf-api] bridge ready → ' + API + '   (window.gfPlaceOrder available)');
})();

/* ── block 3 ─────────────────────────────────────────── */
(function(){
  var fab = document.createElement('button');
  fab.className = 'gf-fab-back';
  fab.setAttribute('aria-label','Go back (drag to move)');
  fab.title = 'Tap = Back · Long-press & drag = Move';
  fab.innerHTML = '←';
  // Mount INSIDE the .phone frame so it appears on the simulated screen
  // (desktop) and on real mobile (where .phone fills the viewport).
  var host = document.querySelector('.phone') || document.body;
  host.appendChild(fab);

  // ── DRAGGABLE: persist position in localStorage ────────────────
  var POS_KEY = 'gf_fab_pos';
  function clamp(v, min, max){ return Math.max(min, Math.min(max, v)); }
  function applyPos(p){
    if (!p || typeof p.left !== 'number' || typeof p.top !== 'number') return;
    var rect = host.getBoundingClientRect();
    var size = 44;
    var left = clamp(p.left, 4, Math.max(4, rect.width  - size - 4));
    var top  = clamp(p.top,  4, Math.max(4, rect.height - size - 4));
    fab.style.left      = left + 'px';
    fab.style.top       = top  + 'px';
    fab.style.right     = 'auto';
    fab.style.bottom    = 'auto';
    fab.style.transform = 'none';     // override the centering translateY
  }
  try {
    var saved = JSON.parse(localStorage.getItem(POS_KEY) || 'null');
    if (saved) applyPos(saved);
  } catch(e){}

  var dragging = false, moved = false, startX = 0, startY = 0, baseL = 0, baseT = 0;
  var DRAG_THRESHOLD = 5; // px before we treat it as a drag (so taps still navigate)

  function pointerDown(ev){
    var pt = ev.touches ? ev.touches[0] : ev;
    dragging = true;
    moved = false;
    var rect = fab.getBoundingClientRect();
    var hostRect = host.getBoundingClientRect();
    baseL = rect.left - hostRect.left;
    baseT = rect.top  - hostRect.top;
    startX = pt.clientX;
    startY = pt.clientY;
    // pin current position so first move doesn't snap from CSS center
    applyPos({ left: baseL, top: baseT });
    fab.style.transition = 'none';
    if (ev.cancelable) ev.preventDefault();
  }
  function pointerMove(ev){
    if (!dragging) return;
    var pt = ev.touches ? ev.touches[0] : ev;
    var dx = pt.clientX - startX;
    var dy = pt.clientY - startY;
    if (!moved && (Math.abs(dx) > DRAG_THRESHOLD || Math.abs(dy) > DRAG_THRESHOLD)) {
      moved = true;
      fab.style.opacity = '0.65';
    }
    if (moved) {
      applyPos({ left: baseL + dx, top: baseT + dy });
      if (ev.cancelable) ev.preventDefault();
    }
  }
  function pointerUp(ev){
    if (!dragging) return;
    dragging = false;
    fab.style.transition = '';
    fab.style.opacity = '';
    if (moved) {
      // save final position
      try {
        var rect = fab.getBoundingClientRect();
        var hostRect = host.getBoundingClientRect();
        localStorage.setItem(POS_KEY, JSON.stringify({
          left: rect.left - hostRect.left,
          top:  rect.top  - hostRect.top,
        }));
      } catch(e){}
      // swallow the click that follows on mouseup
      var swallow = function(e){ e.stopPropagation(); e.preventDefault(); fab.removeEventListener('click', swallow, true); };
      fab.addEventListener('click', swallow, true);
      setTimeout(function(){ fab.removeEventListener('click', swallow, true); }, 50);
    } else {
      // pure tap → navigate back
      if (typeof window.goBack === 'function') window.goBack();
    }
  }

  fab.addEventListener('mousedown',  pointerDown);
  fab.addEventListener('touchstart', pointerDown, { passive:false });
  document.addEventListener('mousemove',  pointerMove);
  document.addEventListener('touchmove',  pointerMove, { passive:false });
  document.addEventListener('mouseup',    pointerUp);
  document.addEventListener('touchend',   pointerUp);
  document.addEventListener('touchcancel',pointerUp);
  // double-click resets to default mid-left position
  fab.addEventListener('dblclick', function(ev){
    ev.preventDefault();
    try { localStorage.removeItem(POS_KEY); } catch(e){}
    fab.style.left = ''; fab.style.top = ''; fab.style.right = ''; fab.style.bottom = ''; fab.style.transform = '';
  });

  // keep it on-screen if the phone frame resizes
  window.addEventListener('resize', function(){
    try {
      var saved = JSON.parse(localStorage.getItem(POS_KEY) || 'null');
      if (saved) applyPos(saved);
    } catch(e){}
  });

  // ── SHOW/HIDE: mirror the top-left back button ─────────────────
  function refresh(){
    var cur = document.querySelector('.screen.active');
    var hasBack = !!(cur && cur.querySelector('.back-btn'));
    fab.classList.toggle('show', hasBack);
  }
  var orig = window.showScreen;
  if (typeof orig === 'function') {
    window.showScreen = function(){
      var r = orig.apply(this, arguments);
      try { refresh(); } catch(e){}
      return r;
    };
  }
  setTimeout(refresh, 300);
})();

