(function(){
  function goProfile(ev){
    if (ev) { ev.stopPropagation(); ev.preventDefault(); }
    if (typeof window.switchTab === 'function') window.switchTab('profile');
    else if (typeof window.showScreen === 'function') window.showScreen('profile');
  }
  // Direct bind on the home-header avatar (id is unique)
  function bind(){
    var av = document.getElementById('user-avatar');
    if (av && !av._gfBound){
      av._gfBound = true;
      av.style.cursor = 'pointer';
      av.setAttribute('role','button');
      av.setAttribute('aria-label','Open profile');
      av.addEventListener('click', goProfile);
      av.addEventListener('touchend', goProfile, { passive:false });
    }
  }
  // Delegated fallback — catches any .user-avatar anywhere in the app
  document.addEventListener('click', function(ev){
    var t = ev.target;
    if (t && t.classList && t.classList.contains('user-avatar') && t.id !== 'profile-avatar'){
      goProfile(ev);
    }
  }, true);
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', bind);
  } else {
    bind();
  }
  // re-bind defensively after any screen change
  var _ss = window.showScreen;
  if (typeof _ss === 'function'){
    window.showScreen = function(){ var r = _ss.apply(this, arguments); try{ bind(); }catch(e){} return r; };
  }
})();

