        + "<div class='ua-task' data-tid='breaks'><div class='ua-task-check'>✓</div><div class='ua-task-emoji'>💧</div><div class='ua-task-body'><div class='ua-task-title'>Complete 3+ WFH breaks daily</div><div class='ua-task-sub'>Hydrate · stretch · plant care</div></div></div>"
