(function(){
  function todayK(){var d=new Date();return d.getFullYear()+'-'+(d.getMonth()+1)+'-'+d.getDate();}
  function loadWfhState(){try{return JSON.parse(localStorage.getItem('gf_wfh_'+todayK())||'{}');}catch(e){return{};}}
  function rewardsTotal(){try{return JSON.parse(localStorage.getItem('gf_growpoints_v1')||'0')||0;}catch(e){return 0;}}
  function streakDays(){
    // Walk back from yesterday, count consecutive days fully completed
    var n=0; var d=new Date(); d.setDate(d.getDate()-1);
    for(var i=0;i<60;i++){
      var k='gf_wfh_'+d.getFullYear()+'-'+(d.getMonth()+1)+'-'+d.getDate();
      try{var s=JSON.parse(localStorage.getItem(k)||'{}');
        var full=['hydrate','sunlight','plant','stretch','meal'].every(function(t){return s[t]});
        if(full){n++; d.setDate(d.getDate()-1);} else break;
      }catch(e){break;}
    }
    return n+1; // include today
  }
  function completionTimeLabel(){
    var s=loadWfhState();
    var times=['hydrate','sunlight','plant','stretch','meal'].map(function(t){return s[t]||0}).filter(Boolean);
    if(!times.length) return '';
    var latest=Math.max.apply(null,times);
    var d=new Date(latest);
    var h=d.getHours(); var m=d.getMinutes();
    var hh=((h+11)%12+1); var ap=h<12?'AM':'PM';
    return hh+':'+(m<10?'0':'')+m+' '+ap;
  }
  function earlyBird(){
    var s=loadWfhState();
    var times=['hydrate','sunlight','plant','stretch','meal'].map(function(t){return s[t]||0}).filter(Boolean);
    if(times.length<5) return false;
    var latest=Math.max.apply(null,times);
    return new Date(latest).getHours()<14; // finished by 2 PM
  }

  function ensureOverlay(){
    var ov=document.getElementById('gf-ach-overlay');
    if(ov) return ov;
    ov=document.createElement('div');
    ov.id='gf-ach-overlay';
    ov.className='ua-overlay';
    ov.innerHTML='<div class="ua-sheet" style="max-height:92%"><div class="ua-handle"></div><button class="ua-close" onclick="closeWfhAchievement()">×</button><div class="ua-body" id="ach-body" style="padding-top:6px"></div></div>';
    ov.addEventListener('click',function(e){ if(e.target===ov) closeWfhAchievement(); });
    var host=document.querySelector('.phone')||document.body;
    host.appendChild(ov);
    return ov;
  }
  window.closeWfhAchievement=function(){ var ov=document.getElementById('gf-ach-overlay'); if(ov) ov.classList.remove('show'); };

  function confettiHtml(){
    var emojis=['🎉','🌿','✨','🌟','🥳','💚','🌸','🏆'];
    var out='';
    for(var i=0;i<14;i++){
      var e=emojis[i%emojis.length];
      var left=Math.round(Math.random()*92);
      var delay=(Math.random()*1.6).toFixed(2);
      var dur=(1.6+Math.random()*1.6).toFixed(2);
      out+='<div class="gf-ach-confetti" style="left:'+left+'%;animation-delay:'+delay+'s;animation-duration:'+dur+'s">'+e+'</div>';
    }
    return out;
  }

  function defaultShareText(opts){
    var name=(typeof window.gfFirstName==='function'?window.gfFirstName():'I');
    var streak=opts.streak||1;
    var time=opts.time||'today';
    var bird=opts.early?' as an Early Bird 🌅':'';
    return '✨ '+name+' just completed the "1 Hour for Yourself" challenge'+bird+'! '+
           'All 5 micro-breaks done by '+time+'. '+
           (streak>1?'🔥 '+streak+'-day streak.':'')+
           '\n\nWho\'s joining me today? Take 1 hour for yourself — hydrate 💧 · sunlight ☀️ · plant care 🌿 · stretch 🧘 · fresh meal 🥗. '+
           '#1HourForYourself #GrowFreshChallenge';
  }

  window.openWfhAchievement=function(){
    var ov=ensureOverlay();
    var body=document.getElementById('ach-body');
    var early=earlyBird();
    var time=completionTimeLabel();
    var streak=streakDays();
    var pts=rewardsTotal();
    var labels={hydrate:'💧 Hydrated',sunlight:'☀️ Got sunlight',plant:'🌿 Plant care done',stretch:'🧘 Stretched',meal:'🥗 Fresh meal'};
    var rows=['hydrate','sunlight','plant','stretch','meal'].map(function(t){return '<div class="row"><div class="ck">✓</div>'+labels[t]+'</div>'}).join('');
    var badges='<div class="b">🔥 '+streak+'-day streak</div>'+(early?'<div class="b">🌅 Early Bird</div>':'')+'<div class="b">💚 Self-care hero</div>';
    body.innerHTML=''+
      '<div class="gf-ach-hero">'+
        confettiHtml()+
        '<div class="medal">🏅</div>'+
        '<div class="ttl">You did it! 1 Hour for Yourself ✨</div>'+
        '<div class="sub">All 5 breaks complete'+(time?' · finished by '+time:'')+'</div>'+
        '<div class="badges">'+badges+'</div>'+
      '</div>'+
      '<div class="gf-ach-stat-row">'+
        '<div class="gf-ach-stat"><div class="n">5/5</div><div class="l">Breaks</div></div>'+
        '<div class="gf-ach-stat"><div class="n">'+streak+'🔥</div><div class="l">Day streak</div></div>'+
        '<div class="gf-ach-stat"><div class="n">'+pts+'</div><div class="l">GrowPts</div></div>'+
      '</div>'+
      '<div class="gf-ach-recap">'+
        '<div class="gf-ach-recap-ttl">📋 Today\'s wins</div>'+rows+
      '</div>'+
      '<div class="gf-ach-share-card">'+
        '<div class="h">📣 Inspire your community</div>'+
        '<div style="font-size:11px;color:#2E7D32;font-weight:700;margin-top:4px;line-height:1.45">Share your win — one post can spark a chain of healthy habits across your community. <b>+15 GrowPts</b> on share.</div>'+
        '<textarea id="ach-share-text" maxlength="280">'+defaultShareText({streak:streak,time:time,early:early})+'</textarea>'+
      '</div>'+
      '<div class="gf-ach-cta-row">'+
        '<button class="gf-ach-skip-btn" onclick="closeWfhAchievement()">Later</button>'+
        '<button class="gf-ach-share-btn" id="ach-share-btn">🚀 Share to Community</button>'+
      '</div>';
    body.querySelector('#ach-share-btn').onclick=function(){
      var text=(body.querySelector('#ach-share-text').value||'').trim();
      if(text.length<10){ if(window.showToast)showToast('⚠️ Write a short note before sharing'); return; }
      // Push to community feed
      try{
        if(typeof initCommunity==='function') initCommunity(); // ensures window.communityPosts is populated
        var AC=window.AC||['#43A047','#FF6F00','#1976D2','#8E24AA','#E53935'];
        var post={
          id:Date.now(),
          author:(typeof window.gfUserName==='function'?window.gfUserName():(window._userName||'You')),
          color:AC[Math.floor(Math.random()*AC.length)],
          time:'Just now',
          type:'tip',
          badge:'badge-tip',
          plant:'🏅 1 Hour for Yourself',
          content:text,
          hasImage:true,
          imageEmoji:'🏅✨🌿',
          likes:0,comments:0,saved:false,liked:false
        };
        // Push to the array AND to localStorage directly, so the next renderCommunityFeed picks it up
        var existing=[];
        try{ existing=JSON.parse(localStorage.getItem('gf_s5_posts')||'[]')||[]; }catch(e){}
        existing.unshift(post);
        try{ localStorage.setItem('gf_s5_posts', JSON.stringify(existing)); }catch(e){}
        if(window.communityPosts && window.communityPosts.unshift){
          window.communityPosts.unshift(post);
        } else {
          window.communityPosts=existing;
        }
      }catch(e){}
      // ALWAYS persist the shared pid for today so the WFH widget routes to it next time
      try{ localStorage.setItem('gf_wfh_shared_pid_'+todayK(), String(post.id)); }catch(e){}
      if(window.gfRewards) window.gfRewards.award(15, '📣 Shared 1 Hour win', { daily:'wfh_share_'+todayK() });
      if(window.showToast) showToast('🚀 Posted! Your win is now in Community');
      closeWfhAchievement();
      // Refresh the home WFH card immediately so the "✓ Shared" ribbon shows on return
      try{ if(typeof window.renderWfh==='function') window.renderWfh(); }catch(e){}
      // Switch to community and highlight the new post (deferred to allow tab transition)
      try{
        if(typeof window.openCommunityPost==='function'){ setTimeout(function(){window.openCommunityPost(post.id);},120); }
        else if(typeof window.switchTab==='function'){ window.switchTab('community'); }
      }catch(e){}
    };
    ov.classList.add('show');
  };
})();

